import{_ as r,o as t,c as a,a2 as i}from"./chunks/framework.BflysNKA.js";const u=JSON.parse('{"title":"接入 Cherry Studio","description":"","frontmatter":{},"headers":[],"relativePath":"apps/cherry-studio.md","filePath":"apps/cherry-studio.md","lastUpdated":1778577020000}'),l={name:"apps/cherry-studio.md"};function o(n,e,d,s,p,h){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="接入-cherry-studio" tabindex="-1">接入 Cherry Studio <a class="header-anchor" href="#接入-cherry-studio" aria-label="Permalink to &quot;接入 Cherry Studio&quot;">​</a></h1><p>Cherry Studio 是桌面端 AI 客户端，适合图形界面对话、多模型切换和代码讨论。</p><p>很多人第一次接入 小蓝中转站，会先用 Cherry Studio 跑第一条链路。原因很直接：</p><ul><li>图形界面里能直接看到服务商、Key、模型和会话切换位置</li><li>配好后发一句“你好”，最容易先确认地址、鉴权和模型是否都正常</li><li>就算后面你真正主力使用 Claude Code 或 Codex，先把 Cherry Studio 跑通，也能先排除账号、余额和 Key 层的问题</li></ul><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><p>下载入口：</p><ul><li>官网：<a href="https://www.cherry-ai.com/" target="_blank" rel="noreferrer">https://www.cherry-ai.com/</a></li><li>官方下载页：<a href="https://docs.cherry-ai.com/cherry-studio/download" target="_blank" rel="noreferrer">https://docs.cherry-ai.com/cherry-studio/download</a></li><li>官方文档：<a href="https://docs.cherry-ai.com/" target="_blank" rel="noreferrer">https://docs.cherry-ai.com/</a></li><li>GitHub 发布页：<a href="https://github.com/CherryHQ/cherry-studio/releases" target="_blank" rel="noreferrer">https://github.com/CherryHQ/cherry-studio/releases</a></li></ul><p>国内用户优先打开官方下载页。这个页面已经把官网主线路、GitHub、备用线路和夸克网盘下载整理在一起，通常比只盯着 GitHub 更省事。</p><p>下载顺序建议：</p><ol><li>官方下载页里的主线路</li><li>官方下载页里的备用线路或夸克网盘</li><li>GitHub 发布页</li></ol><p>安装包选择：</p><ul><li>Windows：第一次安装优先选 <code>Setup</code> 安装版；不想写注册表或没有安装权限时，再选 <code>Portable</code> 便携版</li><li>macOS Apple 芯片：选择 <code>arm64</code> / <code>aarch64</code></li><li>macOS Intel 芯片：选择 <code>x64</code> / <code>x86_64</code></li><li>Linux：优先选择 <code>.AppImage</code>，Ubuntu / Debian 也可以选 <code>.deb</code></li></ul><p>官方下载页还说明了两点：</p><ul><li>Windows 7 不支持安装 Cherry Studio</li><li>macOS 下载时要分清 Intel 和 Apple Silicon</li></ul><p>macOS 首次打开如果被系统拦截，到 <strong>系统设置 → 隐私与安全性</strong> 允许打开。 Windows 如果被安全软件拦截，确认下载来源是官网或官方 GitHub 后再放行。</p><h2 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h2><h3 id="_1-准备你的网关凭证" tabindex="-1">1. 准备你的网关凭证 <a class="header-anchor" href="#_1-准备你的网关凭证" aria-label="Permalink to &quot;1. 准备你的网关凭证&quot;">​</a></h3><p>前往 小蓝中转站控制台，为桌面客户端生成一把专用 Key，建议命名为 <code>Desktop-Cherry</code>。</p><p>第一次配置时，建议这样准备：</p><table tabindex="0"><thead><tr><th>项目</th><th>建议</th><th>原因</th></tr></thead><tbody><tr><td>分组</td><td><code>auto</code> 或默认分组</td><td>先把链路跑通</td></tr><tr><td>模型权限</td><td>个人自用先不额外限制</td><td>先减少误判</td></tr><tr><td>第一个模型</td><td>先选轻量模型</td><td>先确认地址、Key 和模型链路都正常</td></tr><tr><td>第二个模型</td><td>再补一个强模型</td><td>后面切到代码、长文任务更方便</td></tr></tbody></table><p>还没创建 Key 时，先看 <a href="/guide/create-key">创建专属 Key</a>。</p><h3 id="_2-添加-openai-兼容服务商" tabindex="-1">2. 添加 OpenAI 兼容服务商 <a class="header-anchor" href="#_2-添加-openai-兼容服务商" aria-label="Permalink to &quot;2. 添加 OpenAI 兼容服务商&quot;">​</a></h3><p>打开 Cherry Studio 的设置中心，找到<strong>自定义服务商 / OpenAI 兼容接口</strong>，填入以下配置：</p><ul><li><strong>API 地址 (Base URL)</strong>：<code>https://xiaolan1.cn</code></li><li><strong>API Key</strong>：填入你刚准备好的凭证。</li><li><strong>获取模型列表</strong>：点击客户端自带的“拉取/获取模型”按钮，小蓝中转站 网关会自动下发你当前权限内的所有可用模型；或者你可以直接从<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>复制特定的模型代号手动添加。</li></ul><p>常见入口名称可能略有不同：</p><ul><li>自定义服务商</li><li>OpenAI Compatible</li><li>OpenAI 兼容</li><li>自定义 OpenAI</li></ul><p>看到这些入口，都可以按上面的地址和 Key 填。</p><p>这里要注意一层：<br> Cherry Studio 里常常同时能看到 OpenAI、Anthropic、Gemini 或其他内置服务商入口。接 小蓝中转站 时，优先找的是 <strong>OpenAI 兼容 / 自定义服务商</strong> 这一类入口，而不是直接把 小蓝中转站 填进别的官方服务商模板里。</p><p>最容易填错的是地址。<br> Cherry Studio 官方当前对服务商地址的说明是：如果服务商给你的完整接口长得像 <code>https://xxx/v1/chat/completions</code>，那在 Cherry Studio 里通常只填根地址，让客户端自己继续补后面的 OpenAI 兼容路径。</p><p>在 Cherry Studio 里，<code>https://xiaolan1.cn</code> 比 <code>https://xiaolan1.cn/v1</code> 更稳。<br> 如果把 <code>/v1</code> 也一起填进去，Cherry Studio 继续补路径后，最终请求就可能多拼一层。</p><h3 id="_3-保存后先做一次校验" tabindex="-1">3. 保存后先做一次校验 <a class="header-anchor" href="#_3-保存后先做一次校验" aria-label="Permalink to &quot;3. 保存后先做一次校验&quot;">​</a></h3><p>Cherry Studio 官方当前在服务商设置里提供 <code>Check</code> 校验按钮。<br> 保存服务商后，先点一次 <code>Check</code>，再继续拉模型，会比直接开新会话更容易判断问题卡在哪一层。</p><p>这一层主要是在确认：</p><ul><li>地址能不能连通</li><li>Key 有没有填错</li><li>当前服务商是不是已经启用</li></ul><p>当前版本的界面右上角还有启用开关时，也顺手确认一下它已经打开。</p><p>这一步已经失败时，先不要急着改模型。<br><code>Check</code> 失败时，问题通常还停留在地址、Key、服务商启用状态或本地网络这一层。</p><h3 id="_4-先把模型列表拉下来" tabindex="-1">4. 先把模型列表拉下来 <a class="header-anchor" href="#_4-先把模型列表拉下来" aria-label="Permalink to &quot;4. 先把模型列表拉下来&quot;">​</a></h3><p>通过 <code>Check</code> 以后，再点“获取模型”或“拉取模型列表”。</p><p>第一次拉完后，重点看三件事：</p><ul><li>列表里有没有你当前想用的模型系列</li><li>模型名是不是完整的</li><li>当前会话下拉框里能不能真的选到这些模型</li></ul><p>已经知道后面会做两类事情时，第一次拉完后就可以顺手分一下：</p><ul><li>一个轻量模型：拿来验证链路、日常聊天、短问答</li><li>一个强模型：拿来做长文、代码、多轮复杂问题</li></ul><p>这样后面切换时不会只看到一长串模型名，却不知道先选哪个。</p><p>如果自动拉取失败，再回<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>复制模型名手动添加。</p><p>模型已经拉下来，不代表当前对话一定已经在用它。<br> 很多时候设置页里能看到模型，真正开新会话时却还停留在旧服务商或旧模型，所以回到对话页后，最好再看一眼当前线程顶部或下拉框里实际选中的模型。</p><h3 id="_5-测试对话" tabindex="-1">5. 测试对话 <a class="header-anchor" href="#_5-测试对话" aria-label="Permalink to &quot;5. 测试对话&quot;">​</a></h3><p>保存配置后，开启一个新对话。选择模型，发送一句“你好”。能正常回复，说明配置已生效。</p><p>第一次测试建议使用轻量模型，先确认鉴权和网络没问题。再切到 Claude、Gemini 或更强模型处理长文和代码。</p><p>第一次真正算接通，通常要同时满足：</p><ol><li><code>Check</code> 成功</li><li>模型列表能拉下来，或手动添加后能被当前会话选中</li><li>发一句短消息能正常返回</li><li>当前线程里显示的确实是你刚选的那个模型</li></ol><h2 id="推荐配置方式" tabindex="-1">推荐配置方式 <a class="header-anchor" href="#推荐配置方式" aria-label="Permalink to &quot;推荐配置方式&quot;">​</a></h2><h3 id="自动获取模型" tabindex="-1">自动获取模型 <a class="header-anchor" href="#自动获取模型" aria-label="Permalink to &quot;自动获取模型&quot;">​</a></h3><p>如果 Cherry Studio 提供“获取模型”按钮，优先点击它。模型列表来自当前 Key 的权限范围。</p><p>获取后重点看：</p><ul><li>模型名是否完整</li><li>是否包含你要用的系列</li><li>价格是否已在模型广场确认</li></ul><p>拉到列表以后，不等于当前会话一定已经切过去了。<br> 很多人看到模型已经在设置页里出现，就以为配置结束了，结果开新会话时还在用别的服务商或别的旧模型。</p><p>最稳的做法是：回到对话页，再看一眼当前线程实际选中的服务商和模型。</p><h3 id="手动添加模型" tabindex="-1">手动添加模型 <a class="header-anchor" href="#手动添加模型" aria-label="Permalink to &quot;手动添加模型&quot;">​</a></h3><p>自动获取失败时，打开 <a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>，复制模型名后手动添加。</p><p>不要手动输入模型名。多一个空格、少一个日期后缀，都可能导致模型不存在。</p><h3 id="多模型分工" tabindex="-1">多模型分工 <a class="header-anchor" href="#多模型分工" aria-label="Permalink to &quot;多模型分工&quot;">​</a></h3><p>建议至少准备两类模型：</p><ul><li>日常聊天：轻量模型，响应快、成本低</li><li>代码和长文：强模型，适合复杂任务</li></ul><p>Cherry Studio 可以保存多个会话，适合把聊天、代码分析、翻译总结分开。</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li><strong>工作流分离</strong>：利用 Cherry Studio 的多会话特性，把聊天、代码分析、翻译总结分开。</li><li><strong>温度控制</strong>：要求严谨的编码任务，可以在客户端侧边栏将 <code>Temperature</code> 调低。</li><li><strong>Key 隔离</strong>：桌面客户端单独一把 Key，和 Claude Code、Codex 分开。</li><li><strong>上下文控制</strong>：避免一次拖入整个仓库。只放相关文件，响应会更快，费用也更稳。</li><li><strong>先校验再聊天</strong>：先点 <code>Check</code>，再拉模型，再发消息，排障顺序会更清楚。</li><li><strong>先轻后强</strong>：先用轻量模型把链路跑通，再切强模型，最容易分清问题是在配置层还是模型层。</li></ul><h2 id="排障" tabindex="-1">排障 <a class="header-anchor" href="#排障" aria-label="Permalink to &quot;排障&quot;">​</a></h2><ul><li><strong>获取不到模型列表？</strong> 先检查 API 地址是不是误写成了 <code>https://xiaolan1.cn/v1</code>，再看 API Key 是否多复制了空格。</li><li><strong>地址填成了 <code>https://xiaolan1.cn/v1</code> 会怎样？</strong> Cherry Studio 可能会继续往后拼 OpenAI 兼容路径，最后看起来像“接口不存在”或“模型列表始终拉不下来”。</li><li><strong>回复极慢或断流？</strong> 去<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>确认该模型当前的拥挤状态，或者切一个轻量级模型交叉验证是否为本地网络波动。</li><li><strong>401 / 鉴权失败？</strong> 重新复制 Key。确认没有前后空格，控制台里这把 Key 没有禁用，余额没有耗尽。</li><li><strong>404 / 模型不存在？</strong> 回模型广场复制模型名。不要使用客户端内置的旧模型名。</li><li><strong>保存后仍然走旧配置？</strong> 关闭 Cherry Studio 后重新打开。多服务商并存时，确认当前会话选中的是 小蓝中转站 服务商。</li><li><strong>能拉到模型，但发消息时报模型不存在？</strong> 先确认当前会话真正选中的是刚拉下来的模型，再检查这把 Key 的分组和模型权限。</li><li><strong>流式回复中途断开？</strong> 先换轻量模型测试。如果轻量模型稳定，大概率是当前模型负载高或上下文太长。</li><li><strong>公司网络无法访问？</strong> 换手机热点测试一次。热点可用时，说明是当前网络策略拦截。</li></ul><h2 id="最小可用配置" tabindex="-1">最小可用配置 <a class="header-anchor" href="#最小可用配置" aria-label="Permalink to &quot;最小可用配置&quot;">​</a></h2><p>只填这三项即可开始：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>服务商类型：OpenAI 兼容</span></span>
<span class="line"><span>API 地址：https://xiaolan1.cn</span></span>
<span class="line"><span>API Key：sk-你的专属Key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>模型名从模型广场复制。其他高级参数先保持默认。<br> 保存后先点 <code>Check</code>，再拉模型，再开新会话测试，会更稳。</p>`,72)])])}const b=r(l,[["render",o]]);export{u as __pageData,b as default};
